const items = $input.all();
let allJobs = [];

for (const item of items) {
  const d = item.json;

  // ── JSearch (object with d.data array) ───────────────────────────────────
  if (d.data && Array.isArray(d.data)) {
    for (const j of d.data) {
      allJobs.push({
        job_id:      'jsearch_' + j.job_id,
        title:       j.job_title || '',
        company:     j.employer_name || '',
        location:    j.job_is_remote ? 'Remote' : `${j.job_city||''} ${j.job_country||''}`.trim(),
        is_remote:   j.job_is_remote === true,
        apply_url:   j.job_apply_link || '',
        description: (j.job_description || '').substring(0, 3000),
        salary_min:  j.job_min_salary || null,
        salary_max:  j.job_max_salary || null,
        salary_text: '',
        posted_date: j.job_posted_at_timestamp
          ? new Date(j.job_posted_at_timestamp * 1000).toISOString().split('T')[0] : '',
        source: 'JSearch'
      });
    }
  }

  // ── Adzuna (results array + count number) ────────────────────────────────
  else if (d.results && Array.isArray(d.results) && typeof d.count === 'number') {
    for (const j of d.results) {
      allJobs.push({
        job_id:      'adzuna_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.title || '',
        company:     (j.company && j.company.display_name) || '',
        location:    (j.location && j.location.display_name) || '',
        is_remote:   ((j.title||'') + ' ' + (j.description||'')).toLowerCase().includes('remote'),
        apply_url:   j.redirect_url || '',
        description: (j.description || '').substring(0, 3000),
        salary_min:  j.salary_min || null,
        salary_max:  j.salary_max || null,
        salary_text: '',
        posted_date: j.created ? j.created.split('T')[0] : '',
        source: 'Adzuna'
      });
    }
  }

  // ── The Muse (results array + page number) ───────────────────────────────
  else if (d.results && Array.isArray(d.results) && typeof d.page === 'number') {
    for (const j of d.results) {
      if (!j.name) continue;
      allJobs.push({
        job_id:      'muse_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.name || '',
        company:     (j.company && j.company.name) || '',
        location:    'Remote',
        is_remote:   true,
        apply_url:   (j.refs && j.refs.landing_page) || '',
        description: (j.contents || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        salary_min:  null,
        salary_max:  null,
        salary_text: '',
        posted_date: j.publication_date ? j.publication_date.split('T')[0] : '',
        source: 'TheMuse'
      });
    }
  }

  // ── Remotive (jobs array) ─────────────────────────────────────────────────
  else if (d.jobs && Array.isArray(d.jobs)) {
    for (const j of d.jobs) {
      allJobs.push({
        job_id:      'remotive_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.title || '',
        company:     j.company_name || '',
        location:    j.candidate_required_location || 'Remote',
        is_remote:   true,
        apply_url:   j.url || '',
        description: (j.description || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        salary_min:  null,
        salary_max:  null,
        salary_text: j.salary || '',
        posted_date: j.publication_date ? j.publication_date.split('T')[0] : '',
        source: 'Remotive'
      });
    }
  }

  // ── Indeed via RapidAPI (hits array) ─────────────────────────────────────
  else if (d.hits && Array.isArray(d.hits)) {
    for (const j of d.hits) {
      allJobs.push({
        job_id:      'indeed_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.title || '',
        company:     j.company || '',
        location:    (j.location||'').toLowerCase().includes('remote') ? 'Remote' : (j.location || ''),
        is_remote:   (j.location||'').toLowerCase().includes('remote')
                  || ((j.title||'') + ' ' + (j.description||j.summary||'')).toLowerCase().includes('remote'),
        apply_url:   j.url || j.link || '',
        description: (j.description || j.summary || j.snippet || '').substring(0, 3000),
        salary_min:  null,
        salary_max:  null,
        salary_text: j.salary || '',
        posted_date: j.date || j.datePosted || '',
        source: 'Indeed'
      });
    }
  }



  // ── LinkedIn Job Search API (active-jb-24h) — array of rich objects ───────
  else if (Array.isArray(d) && d.length > 0 && d[0].date_posted !== undefined && d[0].organization !== undefined) {
    for (const j of d) {
      if (!j.title) continue;

      // Build location string
      const locs = j.locations_derived || [];
      const locStr = locs.length > 0 ? locs[0] : '';

      // Remote detection: remote_derived flag, location_type TELECOMMUTE, or "remote" in loc/description
      const descLower = (j.description_text || '').toLowerCase().substring(0, 500);
      const isRemote = j.remote_derived === true
        || j.location_type === 'TELECOMMUTE'
        || locStr.toLowerCase().includes('remote')
        || descLower.includes('remote');

      // Salary: salary_raw is a structured object {value: [{value, unitText, currency, ...}]}
      let salMin = null, salMax = null, salText = '';
      if (j.salary_raw && j.salary_raw.value) {
        const vals = j.salary_raw.value;
        if (vals.length === 1) {
          salMin = vals[0].value || null;
          salText = vals[0].currency ? `${vals[0].currency} ${vals[0].value}` : String(vals[0].value || '');
        } else if (vals.length >= 2) {
          salMin = Math.min(...vals.map(v => v.value || 0).filter(v => v > 0)) || null;
          salMax = Math.max(...vals.map(v => v.value || 0)) || null;
        }
      }

      allJobs.push({
        job_id:      'linkedin_' + (j.id || Math.random().toString(36).substr(2, 9)),
        title:       j.title || '',
        company:     j.organization || '',
        location:    isRemote ? 'Remote' : locStr,
        is_remote:   isRemote,
        apply_url:   j.external_apply_url || j.url || '',
        description: (j.description_text || '').substring(0, 3000),
        salary_min:  salMin,
        salary_max:  salMax,
        salary_text: salText,
        posted_date: j.date_posted ? j.date_posted.split('T')[0] : '',
        source: 'LinkedIn'
      });
    }
  }


  // ── LinkedIn individual job object (n8n splits array → one item per job) ──
  else if (d.linkedin_id !== undefined && d.organization !== undefined && d.title) {
    const locs = d.locations_derived || [];
    const locStr = locs.length > 0 ? locs[0] : '';
    const descLower = (d.description_text || '').toLowerCase().substring(0, 500);
    const isRemote = d.remote_derived === true
      || d.location_type === 'TELECOMMUTE'
      || locStr.toLowerCase().includes('remote')
      || descLower.includes('remote');

    let salMin = null, salMax = null, salText = '';
    if (d.salary_raw && d.salary_raw.value) {
      const vals = d.salary_raw.value;
      if (vals.length === 1) {
        salMin = vals[0].value || null;
        salText = vals[0].currency ? `${vals[0].currency} ${vals[0].value}` : String(vals[0].value || '');
      } else if (vals.length >= 2) {
        salMin = Math.min(...vals.map(v => v.value || 0).filter(v => v > 0)) || null;
        salMax = Math.max(...vals.map(v => v.value || 0)) || null;
      }
    }

    allJobs.push({
      job_id:      'linkedin_' + d.id,
      title:       d.title || '',
      company:     d.organization || '',
      location:    isRemote ? 'Remote' : locStr,
      is_remote:   isRemote,
      apply_url:   d.external_apply_url || d.url || '',
      description: (d.description_text || '').substring(0, 3000),
      salary_min:  salMin,
      salary_max:  salMax,
      salary_text: salText,
      posted_date: d.date_posted ? d.date_posted.split('T')[0] : '',
      source: 'LinkedIn'
    });
  }

  // ── Remote OK (top-level array, element 0 is legal notice) ───────────────
  else if (Array.isArray(d)) {
    for (const j of d.slice(1)) {
      if (!j || !j.position) continue;
      allJobs.push({
        job_id:      'remoteok_' + (j.id || Math.random().toString(36).substr(2,9)),
        title:       j.position || '',
        company:     j.company || '',
        location:    'Remote',
        is_remote:   true,
        apply_url:   j.apply_url || j.url || '',
        description: (j.description || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        salary_min:  j.salary_min ? parseInt(j.salary_min) : null,
        salary_max:  j.salary_max ? parseInt(j.salary_max) : null,
        salary_text: '',
        posted_date: j.date ? j.date.split('T')[0] : '',
        source: 'RemoteOK'
      });
    }
  }
}

// Remote-only filter
allJobs = allJobs.filter(j =>
  j.is_remote || j.location.toLowerCase().includes('remote')
);

// ── Hard exclusions (title-based) — drop obvious software/web dev roles ───────
const DEV_TITLES = [
  'software engineer','software developer','software development',
  'web developer','web engineer','frontend','front-end','back-end','backend',
  'full stack','fullstack','full-stack',
  'mobile developer','ios developer','android developer',
  'data engineer','data scientist','ml engineer','machine learning',
  'application developer','application engineer',
  'java developer','python developer','ruby developer','rails developer',
  'react engineer','angular engineer','ui engineer','ux engineer',
  'staff engineer','principal software',
];
allJobs = allJobs.filter(j => {
  const title = j.title.toLowerCase();
  return !DEV_TITLES.some(kw => title.includes(kw));
});

// ── Title must signal infra/ops/network/reliability — not generic "engineer" ─
const TITLE_OK = [
  'sre','site reliability','reliability engineer',
  'network engineer','network architect','network administrator','network operations',
  'infrastructure engineer','infrastructure architect',
  'platform engineer','hybrid cloud engineer','hybrid cloud','cloud engineer','cloud network',
  'devops','dev ops','systems engineer','systems administrator','sysadmin',
  'noc engineer','network security engineer','security engineer',
  'it engineer','it infrastructure','senior engineer',
  'security operations','operations engineer','cloud operations',
  'monitoring engineer','observability engineer','monitoring administrator',
  'site engineer','production engineer','infrastructure operations',
  'network operations center','network analyst','network specialist',
];
allJobs = allJobs.filter(j => {
  const title = j.title.toLowerCase();
  return TITLE_OK.some(kw => title.includes(kw));
});

// ── Exclusion keywords (security/legal) ───────────────────────────────────────
const EXCL = [
  'clearance required','requires clearance','must have clearance','active secret',
  'top secret','ts/sci','secret clearance','drug test','drug screen',
  'pre-employment drug','drug free workplace required'
];
allJobs = allJobs.filter(j => {
  const txt = (j.title + ' ' + j.description + ' ' + j.company).toLowerCase();
  return !EXCL.some(kw => txt.includes(kw));
});

// ── Skip jobs where writing app code is the PRIMARY responsibility ────────────
const CODE_PRIMARY = [
  'building scalable web application','develop backend service',
  'full-stack development','experience with react is required',
  'ruby on rails','django framework','.net development','java spring boot',
  'mobile application development','design and develop software product',
  'software development lifecycle is your','you will write and maintain code',
];
allJobs = allJobs.filter(j => {
  const descTop = j.description.toLowerCase().substring(0, 1000);
  return !CODE_PRIMARY.some(kw => descTop.includes(kw));
});

// ── Defense contractor exclusions ─────────────────────────────────────────────
const DEFENSE = [
  'lockheed martin','raytheon','northrop grumman','booz allen',
  'general dynamics','l3harris','bae systems','leidos'
];
allJobs = allJobs.filter(j =>
  !DEFENSE.some(c => j.company.toLowerCase().includes(c))
);

// Dedup via workflow static data (persists 30 days)
const sd = $getWorkflowStaticData('global');

if (!sd.seenJobIds) sd.seenJobIds = {};
const cutoff = Date.now() - 7 * 24 * 60 * 60 * 1000;
for (const id of Object.keys(sd.seenJobIds)) {
  if (sd.seenJobIds[id] < cutoff) delete sd.seenJobIds[id];
}
const newJobs = allJobs.filter(j => !sd.seenJobIds[j.job_id]);
for (const j of newJobs) sd.seenJobIds[j.job_id] = Date.now();

const limited = newJobs.slice(0, 15);
return [{ json: { jobs: limited, count: limited.length } }];

const resp = $input.first().json;
const { jobs } = $('Format Claude Prompt').first().json;

if (!jobs || jobs.length === 0) {
  return [{ json: { noJobs: true, message: 'No new jobs this run.' } }];
}

let scores = [];
try {
  const raw = resp.candidates[0].content.parts[0].text;
  // Extract JSON array — find first '[' to matching last ']'
  let cleaned = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  const arrStart = cleaned.indexOf('[');
  const arrEnd   = cleaned.lastIndexOf(']');
  if (arrStart !== -1 && arrEnd !== -1 && arrEnd > arrStart) {
    cleaned = cleaned.substring(arrStart, arrEnd + 1);
  }
  scores = JSON.parse(cleaned);
} catch(e) {
  scores = jobs.map((j, i) => ({
    index: i + 1, score: 50,
    fit_summary: 'Auto-scored (parse error).',
    missing_skills: 'Unknown', red_flags: 'None',
    tags: [], role_type: 'Other',
    resume_tips: ['Review job description manually.'],
    cover_letter_hook: 'Please review this position and customize your cover letter accordingly.'
  }));
}

return jobs.map((job, i) => {
  const s = scores.find(x => x.index === i + 1) || {
    score: 50, fit_summary: 'Not scored.',
    missing_skills: 'Unknown', red_flags: 'None',
    tags: [], role_type: 'Other',
    resume_tips: [], cover_letter_hook: ''
  };
  return { json: {
    ...job,
    score:             s.score,
    fit_summary:       s.fit_summary,
    missing_skills:    s.missing_skills,
    red_flags:         s.red_flags,
    tags:              Array.isArray(s.tags) ? s.tags : [],
    role_type:         s.role_type || 'Other',
    resume_tips:       Array.isArray(s.resume_tips) ? s.resume_tips : [s.resume_tips || ''],
    cover_letter_hook: s.cover_letter_hook || ''
  }};
});

const results = [];
const today = new Date().toISOString().split('T')[0];

function descBlocks(text) {
  const blocks = [];
  const safe = (text || '').substring(0, 9500);
  if (!safe) {
    return [{object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content:'(no description available)'}}]}}];
  }
  for (let i = 0; i < safe.length; i += 1900) {
    blocks.push({
      object:'block', type:'paragraph',
      paragraph:{rich_text:[{type:'text',text:{content:safe.substring(i, i+1900)}}]}
    });
  }
  return blocks;
}

function h2(text) {
  return {object:'block',type:'heading_2',heading_2:{rich_text:[{type:'text',text:{content:text}}]}};
}
function divider() { return {object:'block',type:'divider',divider:{}}; }
function bullet(text) {
  return {object:'block',type:'bulleted_list_item',
    bulleted_list_item:{rich_text:[{type:'text',text:{content:text.substring(0,2000)}}]}};
}
function para(text) {
  return {object:'block',type:'paragraph',
    paragraph:{rich_text:[{type:'text',text:{content:(text||'').substring(0,2000)}}]}};
}

for (const item of $input.all()) {
  const j = item.json;

  if (j.noJobs || !j.title) continue;
  if (j.score < 45) continue;

  const tips = Array.isArray(j.resume_tips)
    ? j.resume_tips.filter(t => t && t !== 'None')
    : [];

  const children = [
    h2('📋 Full Job Description'),
    ...descBlocks(j.description),
    divider(),
    h2('🎯 Resume Customization Tips'),
    ...(tips.length > 0
      ? tips.slice(0,8).map(t => bullet(t))
      : [para('No specific tips generated.')]),
    divider(),
    h2('✉️ Cover Letter Hook'),
    para(j.cover_letter_hook || 'Not generated.'),
  ];

  const priority = j.score >= 80 ? 'High' : j.score >= 60 ? 'Medium' : 'Low';
  const tagsValue = (j.tags || []).slice(0, 10).map(t => ({name: String(t).substring(0,100)}));
  const tipsShort = tips.slice(0,3).join(' | ').substring(0,500) || 'None';
  const clShort   = (j.cover_letter_hook || 'None').substring(0,500);

  const body = {
    parent: { database_id: "YOUR_NOTION_DATABASE_ID" },
    properties: {
      "Job Title":          { title:        [{ text: { content: (j.title   || '').substring(0,200) } }] },
      "Company":            { rich_text:    [{ text: { content: (j.company || '').substring(0,200) } }] },
      "Source":             { select:       { name: j.source || 'JSearch' } },
      "Apply URL":          { url: j.apply_url || null },
      "Location":           { rich_text:    [{ text: { content: (j.location || '').substring(0,200) } }] },
      "Salary Min":         { number: j.salary_min || null },
      "Salary Max":         { number: j.salary_max || null },
      "Score":              { number: j.score || 0 },
      "Fit Summary":        { rich_text:    [{ text: { content: (j.fit_summary    || '').substring(0,2000) } }] },
      "Missing Skills":     { rich_text:    [{ text: { content: (j.missing_skills || 'None').substring(0,500) } }] },
      "Red Flags":          { rich_text:    [{ text: { content: (j.red_flags      || 'None').substring(0,500) } }] },
      "Tags":               { multi_select: tagsValue },
      "Role Type":          { select:       { name: j.role_type || 'Other' } },
      "Priority":           { select:       { name: priority } },
      "Resume Tips":        { rich_text:    [{ text: { content: tipsShort } }] },
      "Cover Letter Draft": { rich_text:    [{ text: { content: clShort   } }] },
      "Status":             { select:       { name: 'New' } },
      "Date Found":         { date:         { start: today } },
      "Posted Date":        { rich_text:    [{ text: { content: j.posted_date || '' } }] },
      "Job ID":             { rich_text:    [{ text: { content: (j.job_id || '').substring(0,200) } }] }
    },
    children: children
  };

  results.push({ json: { ...j, notionBody: JSON.stringify(body) } });
}

return results;

const items = $input.all();
if (!items.length || items[0].json.noJobs) {
  return [{ json: {
    discord_content: '**Job Scout** — No new matching jobs found today.',
    email_html: '<p>No new matching jobs found today.</p>',
    email_subject: 'Job Scout: No new jobs today',
    has_jobs: false
  } }];
}

const sorted = [...items].sort((a,b) => b.json.score - a.json.score);
const top5  = sorted.slice(0, 5);
const top20 = sorted.slice(0, 20);
const today = new Date().toLocaleDateString('en-US',
  {weekday:'long',year:'numeric',month:'long',day:'numeric'});

function cleanUrl(url) {
  try { return url.split('?')[0]; } catch(e) { return url; }
}

// Source badge colors for Discord
const srcEmoji = {
  JSearch:'🔷', Adzuna:'🟢', Remotive:'🟣', Indeed:'🔶',
  RemoteOK:'⚫', TheMuse:'🌸', LinkedIn:'🔵'
};

// ── Discord ───────────────────────────────────────────────────────────────────
let discord = `**🔍 Job Scout — ${today}** | ${items.length} new jobs

`;
for (const item of top5) {
  const j = item.json;
  const sal = j.salary_min
    ? " `$" + Math.round(j.salary_min/1000) + "k-" + Math.round((j.salary_max||j.salary_min)/1000) + "k`"
    : (j.salary_text ? " `" + j.salary_text + "`" : "");
  const badge = srcEmoji[j.source] || '⚪';
  const summary = j.fit_summary.length > 100 ? j.fit_summary.substring(0,97) + '...' : j.fit_summary;
  const tags = j.tags && j.tags.length ? ' · ' + j.tags.slice(0,3).join(', ') : '';
  const line = `**${j.score}** — **${j.title}** @ ${j.company}${sal} ${badge}${tags}
${summary}
${cleanUrl(j.apply_url)}

`;
  if ((discord + line).length < 1800) discord += line;
}
discord += `📋 Email has full report | [Notion](<https://www.notion.so/YOUR_NOTION_DATABASE_ID>)\n👉 **Open Notion → change Status to Applied when you apply!**`;

// ── Email ─────────────────────────────────────────────────────────────────────
let emailRows = '';
for (const item of top20) {
  const j = item.json;
  const sal = j.salary_min
    ? '$' + j.salary_min.toLocaleString() + (j.salary_max ? '-$' + j.salary_max.toLocaleString() : '+')
    : (j.salary_text || 'Not listed');
  const c = j.score >= 80 ? '#2d8a4e' : j.score >= 60 ? '#d4940a' : '#c0392b';
  const tagHtml = j.tags && j.tags.length
    ? '<span style="margin-top:4px;display:block">'
      + j.tags.slice(0,6).map(t => `<span style="background:#e8f4f8;color:#2980b9;padding:2px 6px;border-radius:10px;font-size:11px;margin-right:3px">${t}</span>`).join('')
      + '</span>'
    : '';
  emailRows += '<tr style="border-bottom:1px solid #eee">'
    + `<td style="padding:12px;width:60px;text-align:center"><span style="background:${c};color:white;padding:4px 8px;border-radius:12px;font-weight:bold">${j.score}</span>`
    + `<br><span style="font-size:11px;color:#999">${j.source}</span></td>`
    + `<td style="padding:12px"><strong><a href="${j.apply_url}" style="color:#2c3e50;text-decoration:none">${j.title}</a></strong><br>`
    + `<span style="color:#666">${j.company}</span> &nbsp;|&nbsp; `
    + `<span style="color:#888;font-size:13px">${j.location}</span> &nbsp;|&nbsp; `
    + `<span style="color:#27ae60;font-size:13px">${sal}</span><br>`
    + `<span style="color:#555;font-size:13px;display:block;margin-top:4px">${j.fit_summary}</span>`
    + tagHtml
    + `<span style="color:#e67e22;font-size:12px;display:block;margin-top:3px">`
    + (j.resume_tips && j.resume_tips.length ? '📝 ' + (j.resume_tips[0]||'') : '') + '</span>'
    + (j.missing_skills && j.missing_skills !== 'None' ? `<span style="color:#e67e22;font-size:12px">⚠ Missing: ${j.missing_skills}</span>` : '')
    + (j.red_flags && j.red_flags !== 'None' ? `<span style="color:#e74c3c;font-size:12px;display:block">🚩 ${j.red_flags}</span>` : '')
    + `<span style="color:#aaa;font-size:12px"> Posted: ${j.posted_date||'Unknown'}</span>`
    + '</td></tr>';
}

const emailHtml = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:850px;margin:0 auto;color:#333">
<h2 style="color:#2c3e50;border-bottom:3px solid #3498db;padding-bottom:10px">🔍 Job Scout — ${today}</h2>
<p>Found <strong>${items.length} new job(s)</strong> matching your profile. Showing top ${Math.min(20,items.length)}. <a href="https://www.notion.so/YOUR_NOTION_DATABASE_ID">View all in Notion →</a></p>
<table style="width:100%;border-collapse:collapse">
<thead><tr style="background:#3498db;color:white"><th style="padding:10px">Score</th><th style="padding:10px;text-align:left">Job Details</th></tr></thead>
